3	
4	struct AdvancedPane: View {
5	    @Environment(AppContainer.self) private var container
6	
7	    @State private var inflightDownloads: Set<ModelProfile> = []
8	    @State private var inflightRemovals: Set<ModelProfile> = []
9	    @State private var error: String?
10	    @State private var refreshToken = 0  // bumped to force re-read of cacheSize after mutations
11	
12	    @State private var lowDiskPrompt: ModelProfile?
13	    @State private var availableBytes: Int64 = 0
14	
15	    @State private var hfTokenDraft: String = ""
16	    @State private var hfStatus: HFStatus = .idle
17	
18	    /// Trigger the low-disk confirmation when free space on the models volume drops below this.
19	    private let lowDiskThresholdBytes: Int64 = 5 * 1_000_000_000
20	
21	    enum HFStatus: Equatable {
22	        case idle
23	        case testing
24	        case verified(String)
25	        case failed(String)
26	    }
27	
28	    var body: some View {
29	        Form {
30	            Section {
31	                ForEach(ModelProfile.allCases) { profile in
32	                    modelRow(profile)
33	                }
34	            } header: {
35	                Text("Models")
36	            } footer: {
37	                Text("Download additional variants ahead of time, or remove ones you no longer use to reclaim disk space.")
38	                    .font(.caption)
39	                    .foregroundStyle(.secondary)
40	            }
41	            .id(refreshToken)  // Bumps after a download/remove so cacheSize and isDownloaded re-read from disk.
42	
43	            huggingFaceSection
44	
45	            if let error {
46	                Section {
47	                    Text(error)
48	                        .font(.caption)
49	                        .foregroundStyle(.red)
50	                }
51	            }
52	        }
53	        .formStyle(.grouped)
54	        .padding(.horizontal)
55	        .alert(
56	            String(localized: "Disk space low"),
57	            isPresented: Binding(
58	                get: { lowDiskPrompt != nil },
59	                set: { if !$0 { lowDiskPrompt = nil } }
60	            ),
61	            presenting: lowDiskPrompt
62	        ) { profile in
63	            Button(String(localized: "Download anyway"), role: .destructive) {
64	                performDownload(profile)
65	            }
66	            Button(String(localized: "Cancel"), role: .cancel) {}
67	        } message: { _ in
68	            Text("Only \(formatBytes(availableBytes)) free on the models volume. Continue downloading?")
69	        }
70	        .onAppear {
71	            // Don't pre-fill the actual token — show empty field so a fresh save replaces it.
72	            hfTokenDraft = ""
73	            if let v = container.hfTokenStore.verifiedUsername {
74	                hfStatus = .verified(v)
75	            }
76	        }
77	    }
78	
79	    // MARK: - HF section
80	
81	    private var huggingFaceSection: some View {
82	        Section {
83	            HStack {
84	                Text("Token")
85	                Spacer()
86	                if container.hfTokenStore.hasToken {
87	                    StatusBadge(tone: .ok, text: String(localized: "Saved"))
88	                } else {
89	                    StatusBadge(tone: .neutral, text: String(localized: "Not set"))
90	                }
91	            }
92	            SecureField(String(localized: "hf_… (paste here, then Save)"), text: $hfTokenDraft)
93	                .textFieldStyle(.roundedBorder)
94	            HStack {
95	                Button(String(localized: "Save token")) {
96	                    saveToken()
97	                }
98	                .disabled(hfTokenDraft.isEmpty)
99	                Button(String(localized: "Test connection")) {
100	                    testConnection()
101	                }
102	                .disabled(!container.hfTokenStore.hasToken)
103	                Spacer()
104	                if container.hfTokenStore.hasToken {
105	                    Button(role: .destructive) {
106	                        clearToken()
107	                    } label: {
108	                        Text(String(localized: "Clear"))
109	                    }
110	                    .controlSize(.small)
111	                }
112	            }
113	            switch hfStatus {
114	            case .idle:
115	                EmptyView()
116	            case .testing:
117	                HStack(spacing: 6) {
118	                    ProgressView().controlSize(.mini)
119	                    Text("Testing…")
120	                        .font(.caption)
121	                        .foregroundStyle(.secondary)
122	                }
123	            case .verified(let user):
124	                Text("Signed in as **\(user)**")
125	                    .font(.caption)
126	                    .foregroundStyle(.green)
127	            case .failed(let msg):
128	                Text(msg)
129	                    .font(.caption)
130	                    .foregroundStyle(.red)
131	                    .lineLimit(2)
132	            }
133	        } header: {
134	            Text("Hugging Face")
135	        } footer: {
136	            Text("Used to push the dataset from the browser window. Token is stored in macOS Keychain.")
137	                .font(.caption)
138	                .foregroundStyle(.secondary)
139	        }
140	    }
141	
142	    private func saveToken() {
143	        do {
144	            try container.hfTokenStore.save(token: hfTokenDraft)
145	            hfTokenDraft = ""
146	            hfStatus = .idle
147	        } catch {
148	            hfStatus = .failed(String(localized: "Keychain save failed: \(error.localizedDescription)"))
149	        }
150	    }
151	
