export const meta = {
  name: 'sparkle-integration-research',
  description: 'Research + adversarially verify the exact Sparkle 2.x auto-update integration for a notarized Developer-ID DMG macOS menu-bar app shipped via GitHub Releases',
  phases: [
    { title: 'Research', detail: 'parallel: Sparkle SwiftUI/AppKit API, code signing under hardened runtime, CI appcast on GitHub Releases, codebase touchpoints' },
    { title: 'Verify', detail: 'adversarially refute the riskiest claims (signing, appcast hosting, Swift 6 concurrency)' },
  ],
}

const FINDINGS = {
  type: 'object',
  additionalProperties: false,
  required: ['summary', 'claims', 'codeOrConfig', 'pitfalls'],
  properties: {
    summary: { type: 'string', description: 'Concise summary of conclusions' },
    claims: {
      type: 'array',
      description: 'Discrete factual claims with confidence and the source that supports each',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['claim', 'confidence', 'source'],
        properties: {
          claim: { type: 'string' },
          confidence: { type: 'string', enum: ['high', 'medium', 'low'] },
          source: { type: 'string', description: 'URL or doc/file reference backing the claim' },
        },
      },
    },
    codeOrConfig: { type: 'string', description: 'Concrete code/config/CLI snippets ready to adapt, with file targets noted' },
    pitfalls: { type: 'array', items: { type: 'string' }, description: 'Gotchas / failure modes to avoid' },
  },
}

const VERDICT = {
  type: 'object',
  additionalProperties: false,
  required: ['claim', 'verdict', 'reasoning', 'correction'],
  properties: {
    claim: { type: 'string' },
    verdict: { type: 'string', enum: ['confirmed', 'refuted', 'needs-nuance'] },
    reasoning: { type: 'string' },
    correction: { type: 'string', description: 'If refuted/needs-nuance, the corrected guidance; else empty' },
  },
}

phase('Research')

const RESEARCH = [
  {
    label: 'sparkle-swiftui-api',
    prompt: `You are researching the CURRENT (2025/2026) Sparkle 2.x API for integrating auto-update into a macOS app. Use WebSearch/WebFetch (load them via ToolSearch first: query "select:WebSearch,WebFetch") to confirm against the official Sparkle docs at https://sparkle-project.org/documentation/ and the sparkle-project/Sparkle GitHub repo.

The target app: macOS 15+, Swift 6 with SWIFT_STRICT_CONCURRENCY=complete, a menu-bar/agent app (LSUIElement=true, NSApp.setActivationPolicy(.accessory)), uses @NSApplicationDelegateAdaptor + an @Observable @MainActor AppContainer, and an NSStatusItem-based NSMenu (NOT SwiftUI Commands). Settings UI is SwiftUI (Form/Section/Picker/Toggle).

Answer concretely:
1. Which Sparkle 2.x version range is current and compatible with macOS 15 + Swift 6 + SwiftPM? Exact package URL + recommended 'from:' version.
2. The canonical way to create and own the updater: SPUStandardUpdaterController — its init params (startingUpdater, updaterDelegate, userDriverDelegate), whether it must be retained, and whether it is main-actor-safe under Swift 6 strict concurrency. How to call checkForUpdates(_:) from an NSMenuItem action (target/selector) AND/OR programmatically.
3. How to expose 'automatically check for updates' and 'automatically download updates' to a SwiftUI Toggle: the SPUUpdater properties automaticallyChecksForUpdates / automaticallyDownloadsUpdates (Bool, KVO), and the recommended pattern (e.g. a small @Observable wrapper or ObservableObject) to bind them. Provide a ready CheckForUpdatesView / view-model pattern that disables the button when canCheckForUpdates is false.
4. Info.plist keys required: SUFeedURL, SUPublicEDKey, and which keys are ONLY needed for sandboxed apps (this app is NOT sandboxed — hardened runtime only). Is SUEnableInstallerLauncherService / SUEnableDownloaderService needed here? Default value of SUEnableAutomaticChecks behavior and how 'prompt-before-install' (check automatically, download+install on user consent) maps to the two Bool properties.
5. Any required first-launch behavior (Sparkle prompting the user to enable automatic checks).

Return strictly the structured schema. Put exact code in codeOrConfig.`,
  },
  {
    label: 'sparkle-codesign-hardened',
    prompt: `You are researching how to ship Sparkle 2.x inside a Developer-ID-signed, NOTARIZED, hardened-runtime, NON-sandboxed macOS app, built via 'xcodebuild archive' + 'xcodebuild -exportArchive' (method=developer-id, manual signing, Developer ID Application). Use WebSearch/WebFetch (load via ToolSearch: "select:WebSearch,WebFetch") and confirm against Sparkle's official docs (https://sparkle-project.org/documentation/ — especially the 'Sandboxing' and code-signing / 'Programmatic Setup' pages) and known GitHub issues.

Answer concretely:
1. What embedded helper bundles ship inside Sparkle.framework 2.x (e.g. Autoupdate, Updater.app, XPCServices Downloader/Installer)? Which exist for non-sandboxed apps vs sandboxed?
2. When integrating via SwiftPM (not manual framework embed), does 'xcodebuild archive' + export with Developer ID automatic-ish manual signing correctly sign all of Sparkle's nested executables/XPC services, so that 'codesign --verify --strict --deep' and notarization pass? Any extra build settings needed (e.g. CODE_SIGN_INJECT_BASE_ENTITLEMENTS, OTHER_CODE_SIGN_FLAGS=--timestamp already set)? Does the SwiftPM integration require any special handling vs the framework integration for signing?
3. Are any hardened-runtime entitlements required or problematic for Sparkle? The app already has: com.apple.security.cs.disable-library-validation, cs.allow-jit, cs.allow-unsigned-executable-memory, automation.apple-events, device.audio-input. Does disable-library-validation help or conflict? Anything that would make notarization reject?
4. Known failure modes: 'code object is not signed at all' for XPCServices, timestamp errors, 'The update is improperly signed', Gatekeeper rejecting the updated app. How to avoid each.
5. Does the running app need write access to its own bundle location for Sparkle to install in place (i.e. installed in /Applications vs ~/Downloads)? Any privileged-helper/authorization prompt for non-sandboxed in-place updates?

Return strictly the structured schema. codeOrConfig = exact build/verify commands or settings to add.`,
  },
  {
    label: 'sparkle-ci-appcast-github',
    prompt: `You are designing the CI step to generate, EdDSA-sign, and host a Sparkle appcast for a macOS app released as a signed+notarized DMG on GitHub Releases (tag-driven, runs on macos-15 GitHub Actions runner). Use WebSearch/WebFetch (load via ToolSearch: "select:WebSearch,WebFetch") and confirm against Sparkle docs (https://sparkle-project.org/documentation/ 'Publishing an update', 'EdDSA' / generate_keys / sign_update / generate_appcast).

Context: existing release.yml builds ThinkAloud-<version>.dmg and runs 'gh release create v<version> <dmg> --generate-notes'. Repo: github.com/JacobLinCool/think-aloud. The release is the LATEST published (non-prerelease) GitHub release.

Answer concretely:
1. EdDSA key management: how 'generate_keys' produces the key pair (private key in Keychain), how to export the private key as a base64 string for a CI secret ('generate_keys -x' / '-p'), and how SUPublicEDKey is derived. Exact commands the user runs locally once.
2. Where to obtain the sign_update / generate_appcast binaries in CI: downloading the official Sparkle release tarball (e.g. from github.com/sparkle-project/Sparkle/releases, the Sparkle-<ver>.tar.xz containing bin/). Give the exact pattern (curl + tar) and note these tools are also inside the SwiftPM artifact under DerivedData but downloading the tarball is more reliable.
3. The STABLE SUFeedURL pattern for GitHub Releases: confirm that 'https://github.com/<owner>/<repo>/releases/latest/download/appcast.xml' always resolves to the latest non-prerelease release's appcast.xml asset, and that the <enclosure url> in the appcast should be the permanent per-release asset URL 'https://github.com/<owner>/<repo>/releases/download/v<version>/ThinkAloud-<version>.dmg'.
4. Whether to use generate_appcast (needs a directory of all update archives + reads key from Keychain) vs manually building a single-item appcast.xml using 'sign_update <dmg> --ed-key-file' to get edSignature+length and templating the XML. For a CI that only has the ONE new DMG (not all historical ones), which is correct and simplest? Provide a complete single-item appcast.xml template with sparkle:version (CFBundleVersion), sparkle:shortVersionString (MARKETING_VERSION), sparkle:minimumSystemVersion=15.0, enclosure with edSignature + length, and how to inject release notes (sparkle:releaseNotesLink to the GitHub release, or embedded <description> CDATA).
5. How sign_update reads the private key in CI from an env/secret (the '--ed-key-file' flag reading a file, or stdin), so we never store it in Keychain on the runner. Exact invocation.
6. Confirm Sparkle compares sparkle:version (build number / CFBundleVersion) for ordering — so CFBundleVersion MUST monotonically increase. Note the existing CI sets CFBundleVersion=GITHUB_RUN_NUMBER (monotonic). Confirm this is compatible.

Return strictly the structured schema. codeOrConfig = exact CI yaml steps + appcast template + local key-gen commands.`,
  },
  {
    label: 'codebase-touchpoints',
    prompt: `Map the EXACT touchpoints to integrate Sparkle auto-update into this repo, following its existing conventions. Read these files in /Users/jacoblincool/Documents/GitHub/think-aloud:
- project.yml (XcodeGen: note 'packages' and target 'info.properties' which GENERATES Info.plist — Info.plist keys must be added there, editing Info.plist directly is overwritten by 'xcodegen generate')
- ThinkAloud/App/AppContainer.swift, ThinkAloud/App/AppDelegate.swift, ThinkAloud/App/ThinkAloudApp.swift
- ThinkAloud/UI/MenuBar/MenuBarController.swift (NSStatusItem NSMenu — where 'Check for Updates…' item goes)
- ThinkAloud/UI/Settings/SettingsScene.swift, GeneralPane.swift, SettingsHelpers.swift, ModelPane.swift (Toggle/Picker conventions, StatusBadge, InfoRow)
- ThinkAloud/Resources/Localizable.xcstrings and InfoPlist.xcstrings (how localization works; String(localized:) usage — Chinese localization present?)
- .github/workflows/release.yml
- ThinkAloud.xcodeproj is committed alongside project.yml — note that 'xcodegen generate' must be re-run after editing project.yml.

Produce a precise, file-by-file change list:
1. project.yml: where to add the Sparkle SPM package, the target dependency, and the Info.plist properties (SUFeedURL, SUPublicEDKey placeholder).
2. New Swift file(s): proposed path + role (an UpdaterController owned by AppContainer; a CheckForUpdatesView for settings). Match the @MainActor @Observable conventions.
3. AppContainer.swift: how to own/start the updater (init vs start()).
4. MenuBarController.swift: exact menu item insertion (title localized, target/selector) and how it reaches the updater via container.
5. SettingsScene.swift / a new 'Updates' pane or addition to GeneralPane: the Toggle bindings + a 'current version' InfoRow + 'Check Now' button, matching existing Form/Section style.
6. Localizable.xcstrings: list every new user-facing string key that needs adding (and note whether zh-Hant/zh-Hans translations exist for other keys so we match).
7. Whether tests reference anything that would break, and whether ThinkAloudTests needs Sparkle.

Return strictly the structured schema. codeOrConfig = the concrete diffs/snippets per file with correct paths.`,
  },
]

const research = await parallel(
  RESEARCH.map((r) => () => agent(r.prompt, { label: r.label, phase: 'Research', schema: FINDINGS }))
)

const valid = research.filter(Boolean)

// Collect the highest-risk claims to adversarially verify.
const riskyClaims = []
for (const r of valid) {
  for (const c of (r.claims || [])) {
    if (c.confidence !== 'high') riskyClaims.push(c.claim)
  }
}
// Always verify these load-bearing claims regardless of stated confidence.
const mustVerify = [
  'SwiftPM-integrated Sparkle 2.x has all nested XPC services / helper executables correctly signed by xcodebuild archive+export with Developer ID, so codesign --verify --strict --deep and notarization pass with no extra steps.',
  'https://github.com/<owner>/<repo>/releases/latest/download/appcast.xml is a stable URL that always resolves to the latest non-prerelease release asset, making it a valid permanent SUFeedURL.',
  'A single-item appcast.xml (describing only the newest release) hosted per-release is sufficient for Sparkle to detect and install updates; generate_appcast over a full archive directory is NOT required.',
  'SPUStandardUpdaterController can be created and used from a @MainActor context under Swift 6 strict concurrency without concurrency violations, and checkForUpdates(_:) can be invoked from an NSMenuItem target/selector.',
  'For a non-sandboxed hardened-runtime app, only SUFeedURL + SUPublicEDKey are required in Info.plist; SUEnableInstallerLauncherService / SUEnableDownloaderService are sandbox-only and must NOT be set here.',
]
const toVerify = Array.from(new Set([...mustVerify, ...riskyClaims])).slice(0, 10)

phase('Verify')

const verdicts = await parallel(
  toVerify.map((claim, i) => () =>
    agent(
      `Adversarially verify this claim about Sparkle 2.x auto-update integration. Try HARD to REFUTE it using WebSearch/WebFetch against official Sparkle docs (https://sparkle-project.org/documentation/) and the sparkle-project/Sparkle GitHub repo/issues (load tools via ToolSearch: "select:WebSearch,WebFetch"). Default to 'needs-nuance' or 'refuted' if you find ANY caveat, version-specific exception, or missing step. Only 'confirmed' if you can positively corroborate it from an authoritative source.

CLAIM: ${claim}

Return the structured verdict with a concrete correction if it is not fully confirmed.`,
      { label: `verify:${i}`, phase: 'Verify', schema: VERDICT }
    )
  )
)

return {
  research: valid,
  verdicts: verdicts.filter(Boolean),
}

