import Observation
import Sparkle
import SwiftUI

@MainActor
@Observable
final class UpdaterModel {
    private let updater: SPUUpdater
    @ObservationIgnored private var observers: [NSKeyValueObservation] = []

    // Mirrors of the KVO-backed Sparkle properties:
    private(set) var canCheckForUpdates: Bool
    var automaticallyChecksForUpdates: Bool {
        didSet { updater.automaticallyChecksForUpdates = automaticallyChecksForUpdates }
    }
    var automaticallyDownloadsUpdates: Bool {
        didSet { updater.automaticallyDownloadsUpdates = automaticallyDownloadsUpdates }
    }

    init(controller: SPUStandardUpdaterController) {
        let updater = controller.updater
        self.updater = updater
        self.canCheckForUpdates = updater.canCheckForUpdates
        self.automaticallyChecksForUpdates = updater.automaticallyChecksForUpdates
        self.automaticallyDownloadsUpdates = updater.automaticallyDownloadsUpdates

        // KVO so the UI reflects changes Sparkle makes itself (e.g. during a check):
        observers.append(updater.observe(\.canCheckForUpdates, options: [.new]) { [weak self] u, _ in
            Task { @MainActor in self?.canCheckForUpdates = u.canCheckForUpdates }
        })
        observers.append(updater.observe(\.automaticallyChecksForUpdates, options: [.new]) { [weak self] u, _ in
            Task { @MainActor in self?.automaticallyChecksForUpdates = u.automaticallyChecksForUpdates }
        })
        observers.append(updater.observe(\.automaticallyDownloadsUpdates, options: [.new]) { [weak self] u, _ in
            Task { @MainActor in self?.automaticallyDownloadsUpdates = u.automaticallyDownloadsUpdates }
        })
    }

    func checkForUpdates() { updater.checkForUpdates() }
}

