    init(controller: SPUStandardUpdaterController) {
        _model = State(initialValue: UpdaterModel(controller: controller))
    }
    var body: some View {
        Section {
            Button(String(localized: "Check for Updates…")) { model.checkForUpdates() }
                .disabled(!model.canCheckForUpdates)
            Toggle(String(localized: "Automatically check for updates"),
                   isOn: Bindable(model).automaticallyChecksForUpdates)
            Toggle(String(localized: "Automatically download updates"),
                   isOn: Bindable(model).automaticallyDownloadsUpdates)
                // "prompt-before-install" = check ON + download OFF; only enable the
                // download toggle once auto-check is on:
                .disabled(!model.automaticallyChecksForUpdates)
        } header: {
            Text("Updates")
        }
    }
}
