```swift
import Foundation
import Observation
import Sparkle

/// Owns the Sparkle updater. SwiftUI observes `canCheckForUpdates` for button enable/disable,
/// and `automaticallyChecksForUpdates` is mirrored to Sparkle's updater. Standard Developer-ID
/// (non-sandboxed) configuration — no XPC installer services needed.
@MainActor
@Observable
final class UpdaterController {
    @ObservationIgnored private let controller: SPUStandardUpdaterController
    private(set) var canCheckForUpdates = false

    var automaticallyChecksForUpdates: Bool {
        get { controller.updater.automaticallyChecksForUpdates }
        set { controller.updater.automaticallyChecksForUpdates = newValue }
    }

    init() {
        // startingUpdater: true schedules the first check after launch per SUScheduledCheckInterval.
        controller = SPUStandardUpdaterController(startingUpdater: true, updaterDelegate: nil, userDriverDelegate: nil)
        // Track canCheckForUpdates for menu/button enablement.
        withObservationTracking {} onChange: { [weak self] in
            Task { @MainActor in self?.refresh() }
        }
        refresh()
    }

    private func refresh() {
        canCheckForUpdates = controller.updater.canCheckForUpdates
    }

    func checkForUpdates() {
        controller.checkForUpdates(nil)
    }
}
```
(Simpler alternative if you don't need reactive `canCheckForUpdates`: drop the observation plumbing and read `controller.updater.canCheckForUpdates` directly at call sites. Sparkle's own `KVO` on `canCheckForUpdates` is what their sample binds to; the above keeps it @Observable-friendly.)

