export const meta = {
  name: 'sparkle-impl-review',
  description: 'Adversarially review the Sparkle auto-update implementation diff for correctness bugs across Swift, build config, and CI',
  phases: [
    { title: 'Review', detail: 'parallel dimension reviewers read the changed files' },
    { title: 'Verify', detail: 'adversarially confirm each finding is real before reporting' },
  ],
}

const FINDINGS = {
  type: 'object',
  additionalProperties: false,
  required: ['findings'],
  properties: {
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['title', 'file', 'severity', 'detail', 'suggestedFix'],
        properties: {
          title: { type: 'string' },
          file: { type: 'string', description: 'path:line' },
          severity: { type: 'string', enum: ['blocker', 'high', 'medium', 'low', 'nit'] },
          detail: { type: 'string' },
          suggestedFix: { type: 'string' },
        },
      },
    },
  },
}

const VERDICT = {
  type: 'object',
  additionalProperties: false,
  required: ['title', 'isReal', 'reasoning', 'finalSeverity'],
  properties: {
    title: { type: 'string' },
    isReal: { type: 'boolean' },
    reasoning: { type: 'string' },
    finalSeverity: { type: 'string', enum: ['blocker', 'high', 'medium', 'low', 'nit', 'not-a-bug'] },
  },
}

const REPO = '/Users/jacoblincool/Documents/GitHub/think-aloud'
const CONTEXT = `Repo: ${REPO}. A Sparkle 2.x auto-update feature was just added to ThinkAloud, a macOS 15+, Swift 6 strict-concurrency, non-sandboxed, hardened-runtime, Developer-ID, notarized, LSUIElement menu-bar app distributed as a DMG via GitHub Releases.

Verified facts (do NOT re-flag these as problems): the app already builds clean with zero warnings; Sparkle 2.9.2 resolves; the built Info.plist contains SUFeedURL/SUPublicEDKey(real key)/SUEnableAutomaticChecks=true/SUAllowsAutomaticUpdates=true/SUScheduledCheckInterval=86400; Sparkle.framework is embedded; Debug uses OTHER_CODE_SIGN_FLAGS=--timestamp=none and Release uses --timestamp; the sign_update CLI was empirically confirmed to accept the private key on stdin via "--ed-key-file -" and emit sparkle:edSignature="…" length="…"; SUEnableInstallerLauncherService/Downloader/sandbox keys are intentionally omitted (sandbox-only); Info.plist is generated by XcodeGen from project.yml; localization is zh-Hant only and 6 new keys were added.

Focus on LOGIC/CORRECTNESS bugs the build can't catch.`

phase('Review')

const DIMENSIONS = [
  {
    label: 'swift-correctness',
    prompt: `${CONTEXT}

Review these Swift files for correctness, Swift-6 concurrency, retain cycles, observation/reactivity, and menu-validation bugs. Read them fully:
- ${REPO}/ThinkAloud/Core/Updater/UpdaterController.swift
- ${REPO}/ThinkAloud/UI/Settings/UpdatesPane.swift
- ${REPO}/ThinkAloud/UI/MenuBar/MenuBarController.swift
- ${REPO}/ThinkAloud/App/AppContainer.swift (updater ownership)
- ${REPO}/ThinkAloud/UI/Settings/SettingsScene.swift

Specifically scrutinize: (a) the NSKeyValueObservation lifetime/threading and whether canCheckForUpdates updates correctly; (b) whether the @Observable/@Bindable wiring actually makes the SwiftUI toggles + button reactive; (c) the NSMenuItemValidation extension — does validateMenuItem get called for an NSStatusItem menu, and does returning true for all other items preserve existing behavior; (d) any main-actor / Sendable hazard; (e) whether the "automatically download" toggle being disabled when checks is off is logically sound. Report only real issues.`,
  },
  {
    label: 'build-config',
    prompt: `${CONTEXT}

Review build/config correctness. Read:
- ${REPO}/project.yml (Sparkle package, dependency, info.properties Sparkle keys, per-config OTHER_CODE_SIGN_FLAGS)
- ${REPO}/ThinkAloud/Resources/Info.plist (generated — check consistency only)
- ${REPO}/ThinkAloud/Resources/Localizable.xcstrings (the 6 new keys: are the keys EXACTLY matching the Swift String(localized:) literals incl. the "…" ellipsis char, and is JSON valid)

Scrutinize: (a) is SUFeedURL's URL exactly consistent with what the CI publishes (releases/latest/download/appcast.xml) and the repo owner/name JacobLinCool/think-aloud; (b) any Sparkle Info.plist key that is wrong/missing/misspelled for a non-sandboxed app; (c) does pinning Sparkle 'from: 2.8.0' have any conflict; (d) any localization key mismatch between the xcstrings entries and the exact strings used in UpdaterController/UpdatesPane/MenuBarController/SettingsScene (e.g. "Check for Updates…", "Automatically download and install updates", "Updates", "Current version", the footer sentence). Report only real issues.`,
  },
  {
    label: 'ci-appcast',
    prompt: `${CONTEXT}

Review the CI appcast generation for correctness. Read:
- ${REPO}/.github/workflows/release.yml (focus on the new "Generate Sparkle appcast" step and the modified "Publish GitHub Release" step)

Scrutinize VERY carefully: (a) the heredoc — after YAML strips the block's common indentation, does the EOF terminator land at column 0 so the heredoc closes correctly? Are there any unescaped characters or unintended shell/command/variable expansions inside the unquoted <<EOF body? (b) is the appcast signed AFTER stapling (so the signature matches the bytes users download)? (c) enclosure URL correctness vs the DMG_NAME and TAG; (d) the SIG_ATTRS injection — sign_update emits 'sparkle:edSignature="…" length="…"', is it placed correctly inside <enclosure>? (e) the secret-missing path (exit 0 + empty steps.appcast.outputs.path) and the bash array ASSETS handling in Publish — does 'set -u' break on an empty/undefined output? (f) does 'date' format string work on the macos-15 runner (BSD date)? (g) sparkle:version=BUILD (run number) vs shortVersionString=VERSION ordering. Report only real issues with exact line references.`,
  },
]

const reviews = await pipeline(
  DIMENSIONS,
  (d) => agent(d.prompt, { label: d.label, phase: 'Review', schema: FINDINGS }),
  (r, d) => {
    const fs = (r && r.findings) || []
    if (!fs.length) return []
    return parallel(fs.map((f) => () =>
      agent(
        `Adversarially verify this code-review finding about the Sparkle integration. Read the actual file at ${REPO} and try to REFUTE it. Many "findings" are false alarms — default to isReal=false unless you can concretely demonstrate the bug by quoting the offending code. ${CONTEXT}

FINDING: ${JSON.stringify(f)}

Return the verdict.`,
        { label: `verify:${d.label}`, phase: 'Verify', schema: VERDICT }
      ).then((v) => ({ ...f, verdict: v }))
    ))
  }
)

const confirmed = reviews.flat().filter(Boolean).filter((f) => f.verdict && f.verdict.isReal)
return { confirmed, allFindingsCount: reviews.flat().length }

